const userName = $("Execute Workflow Trigger").first().json.userName || "User";
const orgName =
  $('Resolve Org Intents').first()?.json?.name || "Organization";
const userMessage = $("Execute Workflow Trigger").first().json.userInput || "";
const messageSource =
  $("Execute Workflow Trigger").first().json.messageSource || "text";
const availableIntents =
  $('Resolve Org Intents').first()?.json?.intents || [];

let alreadyCollectedSection = "";
let filteredIntents = availableIntents;

// A fresh menu button tap always means "start this intent over" — never trust a
// stale session's collected fields in that case, even if the session doc hasn't
// been deleted from the DB yet by the time this node's output was captured.
const session = messageSource === 'button' ? null : $("Fetch Intent Session").first().json;
if (session && session.intentName) {
  filteredIntents = availableIntents.filter(
    (i) => i.name === session.intentName,
  );
  try {
    const collected =
      typeof session.collectedFields === "string"
        ? JSON.parse(session.collectedFields)
        : (session.collectedFields || {});
    if (Object.keys(collected).length > 0) {
      alreadyCollectedSection =
        "\nALREADY COLLECTED FIELDS (CONFIRMED — carry forward as-is):\n" +
        JSON.stringify(collected, null, 2) +
        "\nDO NOT re-ask for any of these fields. Continue with the next uncollected parameter.\n";
    }
  } catch (e) {}
}

function buildParameterGuide(parameters) {
  if (!parameters || parameters.length === 0) return "  No parameters.";
  return parameters
    .map((p) => {
      if (p.type === "repeat_section")
        return (
          '  - PARAMETER_NAME="' +
          p.name +
          '" | Type: repeat_section | THIS IS A MARKER — when all parameters above this are collected (or if there are none), immediately return action="enter_repeat" with nextFieldName="' +
          p.name +
          '". DO NOT collect a value for this field.'
        );
      let line =
        '  - PARAMETER_NAME_COPY_EXACTLY="' +
        p.name +
        '" | Type: ' +
        p.type +
        " | resolvedBy: " +
        p.resolvedBy;
      if (p.description) line += " | Description: " + p.description;
      if (p.validationRule) line += " | Validation Rule: " + p.validationRule;
      if (
        p.type !== "list_buttons" &&
        p.options &&
        Array.isArray(p.options) &&
        typeof p.options[0] === "string"
      )
        line += " | Valid options: " + p.options.join(", ");
      return line;
    })
    .join("\n");
}

const intentSummary = filteredIntents
  .map((intent) => {
    const paramGuide = buildParameterGuide(intent.parameters);
    return (
      "Intent name: " +
      intent.name +
      "\nAction: " +
      intent.action +
      "\nDescription: " +
      intent.description +
      "\nParameters:\n" +
      paramGuide +
      "\nAdditionalInfo: " +
      JSON.stringify(intent.additionalInfo || {})
    );
  })
  .join("\n\n---\n\n");

return [
  {
    json: {
      prompt:
        "\nUSER NAME: " +
        userName +
        "\nORGANIZATION: " +
        orgName +
        "\nMESSAGE SOURCE: " +
        messageSource +
        "\nNEW USER MESSAGE: " +
        userMessage +
        "\n" +
        alreadyCollectedSection +
        "\nAVAILABLE INTENTS:\n" +
        intentSummary +
        "\n",
    },
  },
];

const raw = $input.first().json.output;
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
try { return [{ json: JSON.parse(cleaned) }]; } catch (e) { throw new Error('Parse fail: ' + e.message + ' | ' + raw); }

const parsed = $input.first().json;
const orgDoc = $('Resolve Org Intents').first().json;
const trigger = $("Execute Workflow Trigger").first().json;

// FORCIBLE SLOT FIX
if (parsed.collectedData && parsed.collectedData.fields) {
  for (const key of Object.keys(parsed.collectedData.fields)) {
    const val = parsed.collectedData.fields[key];
    if (typeof val === 'string' && val.startsWith('__date__')) {
      parsed.collectedData.additionalInfo = parsed.collectedData.additionalInfo || {};
      parsed.collectedData.additionalInfo.selectedDate = val;
      delete parsed.collectedData.fields[key];

      parsed.action = 'ask_user';
      parsed.nextFieldName = key;
      parsed.nextFieldType = 'slot';
      parsed.readyForExecution = false;
      parsed.message = "Please select a time slot for the chosen date.";
    } else if (typeof val === 'string' && val === '__change_date__') {
      if (parsed.collectedData.additionalInfo) delete parsed.collectedData.additionalInfo.selectedDate;
      delete parsed.collectedData.fields[key];

      parsed.action = 'ask_user';
      parsed.nextFieldName = key;
      parsed.nextFieldType = 'slot';
      parsed.readyForExecution = false;
      parsed.message = "Please select a different date.";
    }
  }
}

// FORCIBLE SLOT FIX SAFETY NET: the AI agent is instructed to copy a raw
// "__date__..." list-reply id verbatim into collectedData.fields, but if it
// fails to do so (drops the prefix, rewords it, or misassigns the field) the
// fix above never fires and the slot API gets called without selectedDate,
// showing the date list again instead of times. Derive it directly from the
// raw incoming WhatsApp reply instead, which is always reliable.
if (!parsed.collectedData?.additionalInfo?.selectedDate) {
  const rawInput = trigger.userInput || '';
  if (trigger.messageSource === 'list_reply' && rawInput.startsWith('__date__')) {
    const intent = (orgDoc.intents || []).find(i => i.name === parsed.intent)
      || (orgDoc.intents || []).find(i => (i.parameters || []).some(p => p.type === 'slot'));
    const slotParam = intent?.parameters?.find(p => p.type === 'slot');
    if (slotParam) {
      parsed.intent = parsed.intent || intent.name;
      parsed.collectedData = parsed.collectedData || { fields: {}, additionalInfo: {} };
      parsed.collectedData.fields = parsed.collectedData.fields || {};
      parsed.collectedData.additionalInfo = parsed.collectedData.additionalInfo || {};
      parsed.collectedData.additionalInfo.selectedDate = rawInput;
      delete parsed.collectedData.fields[slotParam.name];

      parsed.action = 'ask_user';
      parsed.nextFieldName = slotParam.name;
      parsed.nextFieldType = 'slot';
      parsed.readyForExecution = false;
      parsed.message = "Please select a time slot for the chosen date.";
    }
  }
}

// FORCIBLE SLOT TIME FIX: when the user picks a TIME slot, the list-reply id is a
// JSON blob {date,time,endTime,display,quantity,available} that must be stored
// verbatim as the slot field's value. The model sometimes "helpfully" reformats
// this into a plain ISO datetime string instead, silently dropping endTime/
// display/quantity/available. Derive the field value directly from the raw
// incoming WhatsApp reply instead, which is always reliable.
if (trigger.messageSource === 'list_reply') {
  const rawTimeInput = trigger.userInput || '';
  if (rawTimeInput.startsWith('{') && rawTimeInput.endsWith('}')) {
    let timeSlotData = null;
    try { timeSlotData = JSON.parse(rawTimeInput); } catch (e) {}
    if (timeSlotData && timeSlotData.date && timeSlotData.time) {
      const timeIntent = (orgDoc.intents || []).find(i => i.name === parsed.intent)
        || (orgDoc.intents || []).find(i => (i.parameters || []).some(p => p.type === 'slot'));
      const timeSlotParam = timeIntent?.parameters?.find(p => p.type === 'slot');
      if (timeSlotParam) {
        parsed.intent = parsed.intent || timeIntent.name;
        parsed.collectedData = parsed.collectedData || { fields: {}, additionalInfo: {} };
        parsed.collectedData.fields = parsed.collectedData.fields || {};
        parsed.collectedData.fields[timeSlotParam.name] = timeSlotData;
      }
    }
  }
}

if (parsed.intent && parsed.nextFieldName) {
  const intent = (orgDoc.intents || []).find(i => i.name === parsed.intent);
  if (intent) {
    const param = (intent.parameters || []).find(p => p.name === parsed.nextFieldName);

    // FORCIBLE TYPE GUARD: the model sometimes misclassifies a "slot" parameter as a
    // repeat_section (or plain text) marker. A slot field must always resolve to
    // nextFieldType="slot" with action="ask_user" so the date/time picker fires,
    // regardless of what the LLM decided — this takes priority over the
    // repeat_section override below.
    if (param && param.type === 'slot' && (parsed.nextFieldType !== 'slot' || parsed.action === 'enter_repeat')) {
      return [{ json: { ...parsed, action: 'ask_user', nextFieldType: 'slot' } }];
    }

    if (param && param.type === 'repeat_section') {
      return [{ json: { ...parsed, action: 'enter_repeat', nextFieldType: 'repeat_section',
        collectedData: { fields: Object.fromEntries(Object.entries(parsed.collectedData?.fields || {}).filter(([k]) => k !== parsed.nextFieldName)),
          additionalInfo: parsed.collectedData?.additionalInfo || {} } } }];
    }
  }
}
return [{ json: parsed }];

const ai = $("Override Repeat Detection").first().json;
const intents = $('Resolve Org Intents').first().json.intents;
const mi = intents.find((i) => i.name === ai.intent) || {};
const orgDoc = $('Resolve Org Intents').first().json;
const triggerData = $("Execute Workflow Trigger").first().json;

// Start with AI's collected fields
let fields = JSON.parse(JSON.stringify(ai.collectedData?.fields || {}));

// Merge session's collectedFields (has repeat array) if session exists
try {
  const session = $("Fetch Intent Session").first().json;
  if (session && session.collectedFields) {
    const sessionFields =
      typeof session.collectedFields === "string"
        ? JSON.parse(session.collectedFields)
        : session.collectedFields;
    // Session fields take priority for arrays (repeat data)
    // AI fields take priority for strings (post-repeat data)
    for (const [key, value] of Object.entries(sessionFields)) {
      if (Array.isArray(value) || !fields[key]) {
        fields[key] = value;
      }
    }
  }
} catch (e) {}

return [
  {
    json: {
      intent: ai.intent,
      params: {
        fields,
        additionalInfo: mi.additionalInfo || {},
        userId: triggerData.userId,
        parentOrganizationId: orgDoc.parentOrganizationId,
        responseFields: mi.responseFields || [],
      },
    },
  },
];

const wd = $('Call Webhook').first().json;
const ai = $('Override Repeat Detection').first().json;
const mi = ($('Resolve Org Intents').first().json.intents||[]).find(i=>i.name===ai.intent)||{};
const rg = mi.response||null;

// Only pass the record content to the formatter — never the internal
// intentType/message/resolverName fields, so they can't leak into the reply.
const dataLines = Array.isArray(wd.resolvedData)
  ? wd.resolvedData.join('\n\n')
  : (wd.resolvedData != null ? String(wd.resolvedData) : (wd.message || 'No data.'));

const promptParts = [
  'Format the RECORD DATA below as a WhatsApp message. Plain text only.',
  rg ? 'Open with this exact line, then the record data on new lines: ' + rg : null,
  'Include every line from RECORD DATA verbatim and in the same order — do not omit, reword, or summarize any line (this includes lines such as "Your Token" or "Current token" if present).',
  'Do not mention or infer any status/meta text beyond what is in RECORD DATA (no "fetched successfully", no internal field names).',
  '\nRECORD DATA:\n' + dataLines
].filter(Boolean).join('\n');

return [{ json: { prompt: promptParts } }];

const ai = $("Override Repeat Detection").first().json;
const t = $("Execute Workflow Trigger").first().json;
const orgDoc = $('Resolve Org Intents').first().json;
const intent = (orgDoc.intents || []).find((i) => i.name === ai.intent);
const sectionName = ai.nextFieldName;
const mainIndex = (intent?.parameters || []).findIndex(
  (p) => p.name === sectionName,
);
return [
  {
    json: {
      userId: t.userId,
      phoneNumber: t.phoneNumber,
      intentName: ai.intent,
      organizationIntentId: orgDoc._id,
      parentOrganizationId: orgDoc.parentOrganizationId,
      phase: "repeat",
      currentMainIndex: mainIndex >= 0 ? mainIndex : 0,
      sectionName: sectionName,
      currentCycle: 1,
      currentFieldIndex: 0,
      completedItems: "[]",
      currentItem: "{}",
      collectedFields: JSON.stringify(ai.collectedData?.fields || {}),
      generatedQuestions: "",
      createdAt: new Date().toISOString(),
    },
  },
];

const parsed = $('Override Repeat Detection').first().json;
const orgDoc = $('Resolve Org Intents').first().json;
const phoneNumber = $('Execute Workflow Trigger').first().json.phoneNumber;
const nft = parsed.nextFieldType || 'text';
const nfn = parsed.nextFieldName || null;

function textResp(msg) { return [{ json: { responseType: "text", message: msg } }]; }
function interResp(msg, pl) { return [{ json: { responseType: "interactive", message: msg, interactivePayload: pl } }]; }

if (nft === 'text' || !nfn) return textResp(parsed.message);

const intent = (orgDoc.intents||[]).find(i=>i.name===parsed.intent);
const param = intent?.parameters?.find(p=>p.name===nfn);
if (!param) return textResp(parsed.message);

if (nft === 'slot' && param.slotConfigId) {
  let webhookUrl = "https://polychasial-semimythic-veta.ngrok-free.dev/ai-chat/webhook";
  try {
    webhookUrl = $('Call Webhook').item.node.parameters.url || webhookUrl;
  } catch (e) {}
  const baseUrl = webhookUrl.substring(0, webhookUrl.indexOf('/ai-chat/webhook'));
    const selectedDate = parsed.collectedData?.additionalInfo?.selectedDate;
  const dateParam = selectedDate ? "&selectedDate=" + encodeURIComponent(selectedDate.replace('__date__','')) : "";
  const slotUrl = baseUrl + "/public/slotConfig/" + param.slotConfigId + "/availability?parentOrganizationId=" + (orgDoc.parentOrganizationId || orgDoc._id || "") + dateParam;
  return [{ json: { responseType: '__needs_api__', message: parsed.message, intent: parsed.intent, nextFieldName: nfn, nextFieldType: nft, optionsConfig: { url: slotUrl, method: 'GET', mapping: { id: 'id', title: 'title' } }, collectedData: parsed.collectedData } }];
}

if (!param.options && !param.optionsConfig) return textResp(parsed.message);

if ((param.optionsSource||'static') === 'api' && param.optionsConfig) {
  let apiUrl = param.optionsConfig.url;
  if (apiUrl && apiUrl.startsWith('/')) {
    let webhookUrl = "https://polychasial-semimythic-veta.ngrok-free.dev/ai-chat/webhook";
    try { webhookUrl = $('Call Webhook').item.node.parameters.url || webhookUrl; } catch(e){}
    const baseUrl = webhookUrl.substring(0, webhookUrl.indexOf('/ai-chat/webhook'));
    param.optionsConfig.url = baseUrl + apiUrl;
  }
  return [{ json: { responseType: '__needs_api__', message: parsed.message, intent: parsed.intent, nextFieldName: nfn, nextFieldType: nft, optionsConfig: param.optionsConfig, collectedData: parsed.collectedData } }];
}

const opts = (param.options||[]).map((o,i) => ({ id: typeof o==='string'?o:(o.id||String(i)), title: typeof o==='string'?o:(o.title||'') }));
if (!opts.length) return textResp(parsed.message);

if (nft === 'options' && opts.length <= 3) {
  const btns = opts.map(o=>({type:"reply",reply:{id:o.id,title:o.title.substring(0,20)}}));
  return interResp(parsed.message, {messaging_product:"whatsapp",to:phoneNumber,type:"interactive",interactive:{type:"button",body:{text:parsed.message},action:{buttons:btns}}});
}

const PAGE_SIZE=9; const needsP=opts.length>10;
const rows = (needsP?opts.slice(0,PAGE_SIZE):opts).map(o=>({id:o.id,title:o.title.substring(0,24)}));
if (needsP) rows.push({id:'__page__'+parsed.intent+'__'+nfn+'__2',title:'\u25B6 More options'});
return interResp(parsed.message, {messaging_product:"whatsapp",recipient_type:"individual",to:phoneNumber,type:"interactive",interactive:{type:"list",body:{text:parsed.message},action:{button:"Select an option",sections:[{rows}]}}});

const api=$input.first().json;const p=$('Prep API Req').first().json;
const ph=$('Execute Workflow Trigger').first().json.phoneNumber;
if (api.sections && !p.dataPath) {
  return [{json:{phoneNumber:ph,intentName:p.intent,fieldName:p.nextFieldName,options:JSON.stringify(api.sections),totalCount:api.sections.reduce((acc, s) => acc + (s.rows || []).length, 0),createdAt:new Date().toISOString(),message:p.message,resolvedSections:api.sections}}];
}
let raw=api;if(p.dataPath){for(const k of p.dataPath.split('.'))raw=raw?.[k];}
if(!Array.isArray(raw))raw=[];
const opts=raw.map(i=>({id:String(i[p.mapping.id]||''),title:String(i[p.mapping.title]||'')}));
return [{json:{phoneNumber:ph,intentName:p.intent,fieldName:p.nextFieldName,options:JSON.stringify(opts),totalCount:opts.length,createdAt:new Date().toISOString(),message:p.message,resolvedOptions:opts}}];

const d=$('Map & Prep Cache').first().json;
const ph=d.phoneNumber;const p=$('Prep API Req').first().json;

function paginateSections(sections, page, intentName, fieldName) {
  const PAGE_SIZE = 8;
  const flatRows = [];
  for (const sec of sections) {
    for (const row of sec.rows) {
      flatRows.push({
        sectionTitle: sec.title,
        rowId: row.id,
        rowTitle: row.title
      });
    }
  }
  const totalPages = Math.ceil(flatRows.length / PAGE_SIZE);
  const startIdx = (page - 1) * PAGE_SIZE;
  const endIdx = Math.min(startIdx + PAGE_SIZE, flatRows.length);
  const pageRows = flatRows.slice(startIdx, endIdx);
  const paginatedSections = [];
  const sectionMap = {};
  for (const item of pageRows) {
    if (!sectionMap[item.sectionTitle]) {
      sectionMap[item.sectionTitle] = { title: item.sectionTitle, rows: [] };
      paginatedSections.push(sectionMap[item.sectionTitle]);
    }
    sectionMap[item.sectionTitle].rows.push({ id: item.rowId, title: item.rowTitle });
  }
  const navigationRows = [];
  if (page > 1) {
    navigationRows.push({ id: '__page__' + intentName + '__' + fieldName + '__' + (page - 1), title: '◀ Previous dates' });
  }
  if (page < totalPages) {
    navigationRows.push({ id: '__page__' + intentName + '__' + fieldName + '__' + (page + 1), title: 'More dates & times' });
  }
  if (navigationRows.length > 0) {
    paginatedSections.push({ title: 'Other dates', rows: navigationRows });
  }
  return paginatedSections;
}

if (d.resolvedSections) {
  const sections = d.resolvedSections;
  const totalRows = sections.reduce((acc, s) => acc + (s.rows || []).length, 0);
  const paginated = totalRows <= 10 ? sections : paginateSections(sections, 1, p.intent, p.nextFieldName);
  return [{json:{responseType:"interactive",message:d.message,interactivePayload:{messaging_product:"whatsapp",recipient_type:"individual",to:ph,type:"interactive",interactive:{type:"list",body:{text:d.message},action:{button:"Select an option",sections:paginated}}}}}];
}
const opts=d.resolvedOptions||[];
if(!opts.length)return [{json:{responseType:"text",message:d.message}}];
const PS=9;const needsP=opts.length>10;
const rows=(needsP?opts.slice(0,PS):opts).map(o=>({id:o.id,title:o.title.substring(0,24)}));
if(needsP)rows.push({id:'__page__'+p.intent+'__'+p.nextFieldName+'__2',title:'\u25B6 More options'});
return [{json:{responseType:"interactive",message:d.message,interactivePayload:{messaging_product:"whatsapp",recipient_type:"individual",to:ph,type:"interactive",interactive:{type:"list",body:{text:d.message},action:{button:"Select an option",sections:[{rows}]}}}}}];

const orgDoc = $('Find Organization and intents').first().json;
const rawPhone = $('Execute Workflow Trigger').first().json.phoneNumber || "";

// Consider it an auth intent if it has a formId AND EITHER a fieldName OR a numberField
const authIntents = (orgDoc.intents || []).filter(i => i.auth && i.auth.formId && (i.auth.fieldName || i.auth.numberField));

if (authIntents.length === 0) {
  return [{ json: { ...orgDoc, needsAuthFilter: false } }];
}

// Strip non-digits and get last 10
const cleanPhone = String(rawPhone).replace(/\D/g, '');
const baseNum = cleanPhone.length > 10 ? cleanPhone.slice(-10) : cleanPhone;

const camelCase = (str) => {
  if (!str) return '';
  return str.replace(/(?:^\w|[A-Z]|\b\w)/g, (word, index) => {
    return index === 0 ? word.toLowerCase() : word.toUpperCase();
  }).replace(/\s+/g, '');
};

const orConditions = authIntents.map(i => {
  const f1 = i.auth.fieldName || i.auth.numberField;
  const f2 = camelCase(f1);

  // Use "contains" instead of "ends with" to be safe against trailing whitespace
  const regexQuery = { "$regex": baseNum, "$options": "i" };

  const fieldOrs = [
    { [f1]: regexQuery },
    { [f1 + ".value"]: regexQuery }
  ];

  if (f1 !== f2) {
    fieldOrs.push({ [f2]: regexQuery }, { [f2 + ".value"]: regexQuery });
  }

  return {
    "formid": i.auth.formId,
    "$or": fieldOrs
  };
});

const query = { "$or": orConditions };
return [{ json: { ...orgDoc, needsAuthFilter: true, authQuery: query } }];

// Deep clone to prevent mutating original cached data
const orgDoc = JSON.parse(JSON.stringify($('Find Organization and intents').first().json));

const needs = $('Build Auth Filter Query').first().json.needsAuthFilter;
let authorizedFormIds = [];

if (needs) {
  // If needs is true, this node was reached via 'Fetch Authorized Forms', 
  // meaning $input contains the DDF values returned by the database.
  const ddfValues = $input.all().map(item => item.json);
  authorizedFormIds = ddfValues.map(doc => doc.formid).filter(id => id);
}

const filteredIntents = (orgDoc.intents || []).filter(i => {
  if (!i.auth || !i.auth.formId) return true;
  return authorizedFormIds.includes(i.auth.formId);
});

orgDoc.intents = filteredIntents;
return [{ json: orgDoc }];
